challenge.solution:
class ConfigParser:
    def __init__(self, config):
        self.config = config

    @staticmethod
    def clean_key(key):
        return key.strip().lower()

    @classmethod
    def from_dict(cls, data):
        cleaned = {cls.clean_key(k): v for k, v in data.items()}
        return cls(cleaned)
